local cjson = require("cjson")

-- Simple XML parser that handles entity references
-- Works within OpenResty without external C dependencies

local XmlParser = {}
XmlParser.__index = XmlParser

-- Entity reference mappings
local entity_map = {
    ["&amp;"]  = "&",
    ["&lt;"]   = "<",
    ["&gt;"]   = ">",
    ["&quot;"] = '"',
    ["&apos;"] = "'",
}

local function decode_entities(str)
    if not str then return str end
    -- Handle named entities
    str = str:gsub("(&%w+;)", function(entity)
        return entity_map[entity] or entity
    end)
    -- Handle numeric entities (decimal)
    str = str:gsub("&#(%d+);", function(num)
        return string.char(tonumber(num))
    end)
    -- Handle numeric entities (hex)
    str = str:gsub("&#x(%x+);", function(num)
        return string.char(tonumber(num, 16))
    end)
    return str
end

local function trim(s)
    if not s then return nil end
    return s:match("^%s*(.-)%s*$")
end

-- Parse XML attributes from a tag string
local function parse_attributes(attr_str)
    local attrs = {}
    if not attr_str then return attrs end
    for name, value in attr_str:gmatch('([%w_:%-]+)%s*=%s*"([^"]*)"') do
        attrs[name] = decode_entities(value)
    end
    for name, value in attr_str:gmatch("([%w_:%-]+)%s*=%s*'([^']*)'") do
        attrs[name] = decode_entities(value)
    end
    return attrs
end

-- Recursive XML parser
local function parse_xml_node(xml_str, pos)
    local nodes = {}
    local text_buffer = ""

    while pos <= #xml_str do
        -- Find next tag
        local tag_start = xml_str:find("<", pos)

        if not tag_start then
            -- Remaining text
            local remaining = trim(decode_entities(xml_str:sub(pos)))
            if remaining and #remaining > 0 then
                text_buffer = text_buffer .. remaining
            end
            break
        end

        -- Capture text before this tag
        if tag_start > pos then
            local text = trim(decode_entities(xml_str:sub(pos, tag_start - 1)))
            if text and #text > 0 then
                text_buffer = text_buffer .. text
            end
        end

        -- Check for XML declaration or processing instruction
        if xml_str:sub(tag_start, tag_start + 1) == "<?" then
            local pi_end = xml_str:find("?>", tag_start)
            if pi_end then
                pos = pi_end + 2
            else
                pos = tag_start + 2
            end

        -- Check for comment
        elseif xml_str:sub(tag_start, tag_start + 3) == "<!--" then
            local comment_end = xml_str:find("-->", tag_start)
            if comment_end then
                pos = comment_end + 3
            else
                pos = tag_start + 4
            end

        -- Check for CDATA
        elseif xml_str:sub(tag_start, tag_start + 8) == "<![CDATA[" then
            local cdata_end = xml_str:find("]]>", tag_start)
            if cdata_end then
                local cdata_content = xml_str:sub(tag_start + 9, cdata_end - 1)
                text_buffer = text_buffer .. cdata_content
                pos = cdata_end + 3
            else
                pos = tag_start + 9
            end

        -- Check for closing tag
        elseif xml_str:sub(tag_start, tag_start + 1) == "</" then
            local close_end = xml_str:find(">", tag_start)
            if close_end then
                pos = close_end + 1
            end
            -- Return to parent
            break

        -- Opening tag or self-closing tag
        else
            local tag_end = xml_str:find(">", tag_start)
            if not tag_end then
                pos = tag_start + 1
            else
                local tag_content = xml_str:sub(tag_start + 1, tag_end - 1)
                local self_closing = tag_content:sub(-1) == "/"
                if self_closing then
                    tag_content = tag_content:sub(1, -2)
                end

                -- Extract tag name and attributes
                local tag_name, attr_str = tag_content:match("^([%w_:%-]+)%s*(.*)")
                if tag_name then
                    local node = {
                        tag = tag_name,
                        attrs = parse_attributes(attr_str),
                        children = {},
                        text = nil,
                    }

                    if not self_closing then
                        -- Parse children recursively
                        local child_nodes, new_pos = parse_xml_node(xml_str, tag_end + 1)
                        node.children = child_nodes.children or {}
                        node.text = child_nodes.text
                        pos = new_pos
                    else
                        pos = tag_end + 1
                    end

                    table.insert(nodes, node)
                else
                    pos = tag_end + 1
                end
            end
        end
    end

    local result = {
        children = nodes,
        text = (#text_buffer > 0) and text_buffer or nil,
    }

    return result, pos
end

function XmlParser.parse(xml_str)
    if not xml_str or #xml_str == 0 then
        return nil, "Empty XML input"
    end

    -- Strip DOCTYPE declarations (prevent XXE)
    xml_str = xml_str:gsub("<!DOCTYPE[^>]*>", "")

    local ok, result = pcall(parse_xml_node, xml_str, 1)
    if not ok then
        return nil, "XML parsing error: " .. tostring(result)
    end

    -- Return root element
    if result.children and #result.children > 0 then
        return result.children[1], nil
    end

    return nil, "No root element found"
end

-- Helper: find a child node by tag name (supports namespace prefix matching)
local function find_child(node, tag_name)
    if not node or not node.children then return nil end
    for _, child in ipairs(node.children) do
        if child.tag == tag_name then
            return child
        end
        -- Match ignoring namespace prefix
        local local_name = child.tag:match(":(.+)$")
        if local_name and local_name == tag_name then
            return child
        end
    end
    return nil
end

-- Helper: find all children by tag name
local function find_children(node, tag_name)
    local results = {}
    if not node or not node.children then return results end
    for _, child in ipairs(node.children) do
        if child.tag == tag_name then
            table.insert(results, child)
        else
            local local_name = child.tag:match(":(.+)$")
            if local_name and local_name == tag_name then
                table.insert(results, child)
            end
        end
    end
    return results
end

-- Helper: get text content of a node (recursively)
local function get_text(node)
    if not node then return nil end
    if node.text then return node.text end
    -- Check children for text
    local parts = {}
    if node.children then
        for _, child in ipairs(node.children) do
            local t = get_text(child)
            if t then table.insert(parts, t) end
        end
    end
    if #parts > 0 then
        return table.concat(parts, "")
    end
    return nil
end

-- Helper: convert XML node tree to a Lua table (recursive)
local function node_to_table(node)
    if not node then return nil end

    local result = {}

    -- Add attributes with @ prefix
    if node.attrs then
        for k, v in pairs(node.attrs) do
            result["@" .. k] = v
        end
    end

    -- If node has only text and no children, return text directly
    if node.text and (not node.children or #node.children == 0) then
        if next(result) then
            -- Has attributes, add text as special key
            result["#text"] = node.text
            return result
        end
        return node.text
    end

    -- Process children
    if node.children then
        for _, child in ipairs(node.children) do
            local child_val = node_to_table(child)
            local tag = child.tag

            if result[tag] then
                -- Convert to array if multiple children with same tag
                if type(result[tag]) ~= "table" or not result[tag][1] then
                    result[tag] = { result[tag] }
                end
                table.insert(result[tag], child_val)
            else
                result[tag] = child_val
            end
        end
    end

    if not next(result) then
        return node.text
    end

    return result
end

