local SoapExtractor = {}

-- Extract SOAP Envelope components
function SoapExtractor.parse_envelope(root)
    if not root then
        return nil, "No root node provided"
    end

    local envelope = {
        header = nil,
        body = nil,
        action = nil,
        namespace = nil,
    }

    -- Determine SOAP version from root tag/namespace
    local root_tag = root.tag or ""
    if root_tag:find("Envelope") then
        -- Extract namespace
        if root.attrs then
            for attr_name, attr_val in pairs(root.attrs) do
                if attr_name:find("xmlns") and attr_val:find("schemas.xmlsoap.org") then
                    if attr_val:find("soap/envelope") then
                        envelope.namespace = "soap11"
                    elseif attr_val:find("soap%-envelope") or attr_val:find("soap/envelope") then
                        envelope.namespace = "soap12"
                    end
                end
            end
        end
    end

    -- Find Header and Body
    local header_node = find_child(root, "Header")
    local body_node = find_child(root, "Body")

    if header_node then
        envelope.header = node_to_table(header_node)
    end

    if body_node then
        envelope.body = node_to_table(body_node)
        -- Extract the SOAP action (first child of Body)
        if body_node.children and #body_node.children > 0 then
            local action_node = body_node.children[1]
            envelope.action = action_node.tag
            -- Strip namespace prefix from action
            local local_action = action_node.tag:match(":(.+)$")
            if local_action then
                envelope.action = local_action
            end
        end
    else
        return nil, "SOAP Body not found"
    end

    return envelope, nil
end

-- Extract specific operation parameters from SOAP body
function SoapExtractor.get_operation_params(envelope)
    if not envelope or not envelope.body then
        return nil, "No SOAP body available"
    end

    -- The first element in body is the operation
    -- Its children are the parameters
    local body = envelope.body
    for key, value in pairs(body) do
        if type(key) == "string" and not key:match("^@") then
            if type(value) == "table" then
                return value, nil
            end
        end
    end

    return {}, nil
end

