local function handle_soap_request()
    -- Read request body
    ngx.req.read_body()
    local body = ngx.req.get_body_data()

    if not body then
        -- Body might be in a temp file
        local file_path = ngx.req.get_body_file()
        if file_path then
            local f = io.open(file_path, "r")
            if f then
                body = f:read("*a")
                f:close()
            end
        end
    end

    if not body or #body == 0 then
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say([[<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <soap:Fault>
      <faultcode>soap:Client</faultcode>
      <faultstring>Empty request body</faultstring>
    </soap:Fault>
  </soap:Body>
</soap:Envelope>]])
        return ngx.exit(400)
    end

    -- Validate Content-Type
    local content_type = ngx.req.get_headers()["Content-Type"] or ""
    if not content_type:find("text/xml") and not content_type:find("application/soap%+xml") and not content_type:find("application/xml") then
        ngx.log(ngx.WARN, "SOAP Gateway: Unexpected Content-Type: ", content_type)
    end

    -- Parse the XML
    local root, parse_err = XmlParser.parse(body)
    if not root then
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(string.format([[<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <soap:Fault>
      <faultcode>soap:Client</faultcode>
      <faultstring>XML Parse Error: %s</faultstring>
    </soap:Fault>
  </soap:Body>
</soap:Envelope>]], parse_err))
        return ngx.exit(400)
    end

    -- Extract SOAP envelope components
    local envelope, soap_err = SoapExtractor.parse_envelope(root)
    if not envelope then
        ngx.status = 500
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(string.format([[<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <soap:Fault>
      <faultcode>soap:Server</faultcode>
      <faultstring>SOAP Processing Error: %s</faultstring>
    </soap:Fault>
  </soap:Body>
</soap:Envelope>]], soap_err))
        return ngx.exit(500)
    end

    -- Extract operation parameters
    local params, param_err = SoapExtractor.get_operation_params(envelope)

    -- Log extracted information
    ngx.log(ngx.INFO, "SOAP Gateway - Action: ", envelope.action or "unknown")
    ngx.log(ngx.INFO, "SOAP Gateway - Namespace: ", envelope.namespace or "unknown")
    ngx.log(ngx.INFO, "SOAP Gateway - Params: ", cjson.encode(params or {}))

    -- Extract SOAPAction header if present
    local soap_action_header = ngx.req.get_headers()["SOAPAction"]
    if soap_action_header then
        -- Remove quotes
        soap_action_header = soap_action_header:gsub('^"', ''):gsub('"$', '')
        ngx.log(ngx.INFO, "SOAP Gateway - SOAPAction Header: ", soap_action_header)
    end

    -- ============================================================
    -- Route SOAP actions to backend services
    -- ============================================================

    local action = envelope.action or ""

    -- Example routing table (customize for your services)
    local route_map = {
        ["GetUser"]        = { upstream = "http://user-service:8080/api/getUser",       method = "POST" },
        ["CreateOrder"]    = { upstream = "http://order-service:8080/api/createOrder",   method = "POST" },
        ["GetProduct"]     = { upstream = "http://product-service:8080/api/getProduct",  method = "POST" },
        ["ProcessPayment"] = { upstream = "http://payment-service:8080/api/process",     method = "POST" },
        ["HealthCheck"]    = { upstream = "internal",                                     method = "GET"  },
    }

    local route = route_map[action]

    -- Handle health check internally
    if route and route.upstream == "internal" and action == "HealthCheck" then
        ngx.status = 200
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say([[<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <HealthCheckResponse>
      <Status>OK</Status>
      <Timestamp>]] .. ngx.now() .. [[</Timestamp>
    </HealthCheckResponse>
  </soap:Body>
</soap:Envelope>]])
        return ngx.exit(200)
    end

    if not route then
        -- Unknown action - return SOAP fault
        ngx.status = 500
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(string.format([[<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <soap:Fault>
      <faultcode>soap:Client</faultcode>
      <faultstring>Unknown SOAP action: %s</faultstring>
    </soap:Fault>
  </soap:Body>
</soap:Envelope>]], action))
        return ngx.exit(500)
    end

    -- Store extracted data in ngx.ctx for downstream processing
    ngx.ctx.soap_envelope = envelope
    ngx.ctx.soap_action = action
    ngx.ctx.soap_params = params
    ngx.ctx.soap_header = envelope.header
    ngx.ctx.soap_route = route

    -- Set variables for proxy pass (if using ngx.var based routing)
    ngx.var.upstream_url = route.upstream

    -- Convert SOAP params to JSON for REST backend services
    local json_body = cjson.encode({
        action = action,
        params = params or {},
        headers = envelope.header,
        soap_version = envelope.namespace,
        request_id = ngx.var.request_id,
    })

    -- Set request body for upstream
    ngx.req.set_body_data(json_body)
    ngx.req.set_header("Content-Type", "application/json")
    ngx.req.set_header("X-SOAP-Action", action)
    ngx.req.set_header("X-SOAP-Version", envelope.namespace or "soap11")
    ngx.req.set_header("X-Request-ID", ngx.var.request_id or "")

    ngx.log(ngx.INFO, "SOAP Gateway - Routing action '", action, "' to: ", route.upstream)
end

-- ============================================================
-- Response transformer: Convert JSON response back to SOAP XML
-- ============================================================

local function build_soap_response(action, response_data, soap_version)
    local ns = 'xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/"'
    if soap_version == "soap12" then
        ns = 'xmlns:soap="http://www.w3.org/2003/05/soap-envelope"'
    end

    -- Simple table-to-XML serializer
    local function serialize_value(val, indent)
        indent = indent or "      "
        local parts = {}
        if type(val) == "table" then
            for k, v in pairs(val) do
                if type(k) == "string" and not k:match("^@") then
                    if type(v) == "table" and v[1] then
                        -- Array
                        for _, item in ipairs(v) do
                            if type(item) == "table" then
                                table.insert(parts, indent .. "<" .. k .. ">")
                                table.insert(parts, serialize_value(item, indent .. "  "))
                                table.insert(parts, indent .. "</" .. k .. ">")
                            else
                                local escaped = tostring(item):gsub("&", "&amp;"):gsub("<", "&lt;"):gsub(">", "&gt;")
                                table.insert(parts, indent .. "<" .. k .. ">" .. escaped .. "</" .. k .. ">")
                            end
                        end
                    elseif type(v) == "table" then
                        table.insert(parts, indent .. "<" .. k .. ">")
                        table.insert(parts, serialize_value(v, indent .. "  "))
                        table.insert(parts, indent .. "</" .. k .. ">")
                    else
                        local escaped = tostring(v):gsub("&", "&amp;"):gsub("<", "&lt;"):gsub(">", "&gt;")
                        table.insert(parts, indent .. "<" .. k .. ">" .. escaped .. "</" .. k .. ">")
                    end
                end
            end
        else
            local escaped = tostring(val):gsub("&", "&amp;"):gsub("<", "&lt;"):gsub(">", "&gt;")
            table.insert(parts, indent .. escaped)
        end
        return table.concat(parts, "\n")
    end

    local response_xml = serialize_value(response_data)

    return string.format([[<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope %s>
  <soap:Body>
    <%sResponse>
%s
    </%sResponse>
  </soap:Body>
</soap:Envelope>]], ns, action, response_xml, action)
end

local function transform_response()
    local ctx = ngx.ctx
    if not ctx.soap_action then
        return -- Not a SOAP request, skip transformation
    end

    -- Read upstream response body
    local resp_body = ngx.arg[1]
    local eof = ngx.arg[2]

    -- Buffer the response
    if not ctx.response_buffer then
        ctx.response_buffer = {}
    end

    if resp_body and #resp_body > 0 then
        table.insert(ctx.response_buffer, resp_body)
    end

    if not eof then
        ngx.arg[1] = nil
        return
    end

    -- Combine buffered response
    local full_response = table.concat(ctx.response_buffer)

    -- Try to parse as JSON
    local ok, json_response = pcall(cjson.decode, full_response)
    if not ok then
        -- If not JSON, wrap raw response
        json_response = { result = full_response }
    end

    -- Build SOAP XML response
    local soap_response = build_soap_response(
        ctx.soap_action,
        json_response,
        ctx.soap_envelope and ctx.soap_envelope.namespace or "soap11"
    )

    ngx.arg[1] = soap_response
    ngx.header["Content-Type"] = "text/xml; charset=utf-8"
    ngx.header["Content-Length"] = #soap_response
end

